// Erstes Item referenzieren
const firstItem = $input.first();

// Autor auslesen (Fallback auf null)
const autor = firstItem.json?.Autor ?? null;

// Alle Binary-Property-Namen holen
const binaries = Object.keys(firstItem.binary ?? {});

// Pro Binary ein eigenes Item erzeugen
return binaries.map(name => {
  const binaryData = firstItem.binary[name];

  return {
    json: {
      fileName: name,
      mimeType: binaryData.mimeType,
      autor: autor, // ✅ Autor hier hinzufügen
    },
    binary: {
      data: binaryData,
    },
  };
});

