// 1. KI-Gesamtresponse aus n8n holen
const aiResponse = items[0].json;

// 2. Textfeld mit ```json ... ``` extrahieren
const text =
  aiResponse?.output?.[0]?.content?.[0]?.text;

if (!text || typeof text !== 'string') {
  throw new Error('No output text found in AI response');
}

// 3. ```json Codeblock sauber entfernen
const jsonString = text
  .replace(/```json\s*/i, '')
  .replace(/```$/, '')
  .trim();

// 4. In echtes JSON parsen
let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  throw new Error('Invalid JSON from AI: ' + e.message);
}

// 5. Als echtes n8n-Item zurückgeben
return [
  {
    json: parsed
  }
];

